<Offense id="monster-gishvit--offense" sp={20} cl={20} melee={<>bite +1 (1d4-2), ribbon +3 touch (<Link to="/umr/grab">grab</Link>)</>} space={"2-1/2"} reach={"0"} reachP={"10 ft. with ribbon"} specAtt={[["overwhelm","overwhelm"],["ribbon","ribbon"]]} />
