<Offense id="monster-gloomwing--offense" sp={10} fl={40} flP="good" melee="bite +6 (1d8+2), 2 claws +6 (1d6+2)" space={"10"} reach={"5"} specAtt={[["confusion","confusion"],["implant","implant"],["pheromones","pheromones"]]} />
