<Stats id="monster-goblin_goblin_vulture_pilot--stats" atts={[8,18,13,16,12,6]} bab={3} cmb={1} cmd={15} feats={["Brew Potion","Mounted Archery","Mounted Combat","Throw Anything"]} skills={{"acro":{"b":8},"climb":{"b":3},"stl":{"b":16}}} racial="+4 Ride, +4 Stealth" lang={["C","G","Gl","Gb"]} sq={<>alchemy (alchemy crafting +4, identify potions), discoveries (<Link to="/discovery/explosive_bomb">explosive bomb</Link>, sipping pet), <Link to="/ability/poison_use">poison use</Link>, swift alchemy</>} combat={[["2","Pbarkskin"],["2","Pcure light wounds"],["2","Wa"],["2","Waf"],["2","Wtbs"]]} othergear={[["Mw","MM","Acs"],["Wd"],["2","Qsrs"],"293 gp"]} />
