<Stats id="monster-goezspall--stats" atts={[26,15,25,6,20,21]} bab={16} cmb={25} cmd={38} feats={["Combat Reflexes","Diehard","Dodge","Endurance","Lunge","Mobility","Power Attack","Vital Strike"]} skills={{"climb":{"b":20}}} lang={["Ak"]} sq={<><Link to="/umr/compression">compression</Link>, hibernate, <Link to="/umr/no_breath">no breath</Link></>} />
