<Stats id="monster-gorynych--stats" atts={[27,15,22,12,17,18]} bab={17} cmb={27} cmd={39} feats={["Awesome Blow","Combat Reflexes","Flyby Attack","Improved Bull Rush","Iron Will","Lightning Reflexes","Power Attack","Stand Still",["Weapon Focus"," (bite)"]]} skills={{"bluff":{"b":17},"diplo":{"b":17},"fly":{"b":7}}} lang={["C","D","S"]} sq="multi-headed" />
